import{_ as a,a as i,b as r,m as o}from"./chunks/framework.DhA78p7M.js";const p=JSON.parse('{"title":"clEar: Glasses-Based Beamforming Hearing Aids","description":"Beamforming hearing aids using a glasses-based microphone array to improve speech clarity and spatial context for the hard of hearing.","frontmatter":{"title":"clEar: Glasses-Based Beamforming Hearing Aids","description":"Beamforming hearing aids using a glasses-based microphone array to improve speech clarity and spatial context for the hard of hearing.","longDescription":"clEar is a glasses-based beamforming hearing aid that uses Golomb-spaced microphone arrays, a custom MSMVDR beamforming technique, and a hybrid multi-speaker tracking algorithm to achieve a 71% increase in STOI and 9.9 dB SNR improvement. ISEF Grand Award, CSEF First Place.","date":"2024-5-1"},"headers":[],"relativePath":"blogs/clear/index.md","filePath":"blogs/clear/index.md"}'),s={name:"blogs/clear/index.md"};function n(t,e,c,l,d,m){return i(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="clear-glasses-based-beamforming-hearing-aids-to-improve-speech-clarity" tabindex="-1">clEar: Glasses-Based Beamforming Hearing Aids to Improve Speech Clarity <a class="header-anchor" href="#clear-glasses-based-beamforming-hearing-aids-to-improve-speech-clarity" aria-label="Permalink to “clEar: Glasses-Based Beamforming Hearing Aids to Improve Speech Clarity”">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to “Summary”">​</a></h2><p>Hearing loss is the fourth most prevalent disability worldwide, affecting one in five people, and is correlated with depression, isolation, and decreased life expectancy. Innovation in hearing aids over the last century has focused on miniaturization to overcome stigma. While successful, this focus has resulted in a form-factor with intrinsic physical limitations that hinder directionality and spatial context. Directionality is crucial to communication and social behavior in noisy environments. Hearing aids&#39; diminished directionality reduces speech clarity and spatial perception.</p><p>clEar, a beamforming hearing aid, unlike traditional designs, uses a glasses-based array of microphones to reduce unwanted noise and restore directionality for $200. clEar utilizes Golomb spacing to double audio bandwidth, a custom Multi Source Minimum Variance Distortionless Response (MSMVDR) beamforming technique to improve speech clarity while maintaining auditory transparency, and a hybrid multi-speaker tracking algorithm that integrates accelerometer data to compensate for head motion.</p><p>Evaluation using voices from the LibreSpeech audiobook recordings demonstrated a <strong>71% increase in speech clarity</strong> as measured by Short Term Objective Intelligibility (STOI) and a <strong>9.9 dB increase in Signal-to-Noise Ratio (SNR)</strong> after MSMVDR processing. The hybrid source tracking algorithm exhibited an average error of 3.8°, significantly outperforming the 58° error of a standard GCC based approach.</p><p>The novel array design enables efficient spatial processing and low power wearable implementation. clEar shows that glasses-based beamformers enhance speech clarity and spatial context in a socially-acceptable form-factor and have the potential to dramatically improve the lives of those with hearing loss.</p><h2 id="more-coming-soon" tabindex="-1">More Coming Soon... <a class="header-anchor" href="#more-coming-soon" aria-label="Permalink to “More Coming Soon...”">​</a></h2>',7)])])}const g=a(s,[["render",n]]);export{p as __pageData,g as default};
